// src/pages/Messages.js — Slack-style dual-pane messenger
import React, { useState, useRef, useEffect } from "react";
import { useLocation } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import { MOCK_CONVERSATIONS, MOCK_FRIENDS, GLOBAL_USERS } from "../data/mockData";
import {
  Send, Calendar, Search, Plus, X, Phone, Video,
} from "lucide-react";

const ALL_CONTACTS = [...MOCK_FRIENDS, ...GLOBAL_USERS];

function fresh(user) {
  return {
    id: `conv_${user.id}`,
    user,
    messages: [],
    lastMessage: "Conversation started",
    time: "just now",
  };
}

export default function Messages() {
  const { theme } = useAuth();
  const location = useLocation();
  const params = new URLSearchParams(location.search);
  const openUserId = params.get("user");

  const [convs, setConvs] = useState(() => {
    // If arriving from Discover with a user param, open/create that conv
    if (openUserId) {
      const contact = ALL_CONTACTS.find((c) => c.id === openUserId);
      const existing = MOCK_CONVERSATIONS.find((c) => c.user.id === openUserId);
      if (existing) return MOCK_CONVERSATIONS;
      return contact ? [fresh(contact), ...MOCK_CONVERSATIONS] : MOCK_CONVERSATIONS;
    }
    return MOCK_CONVERSATIONS;
  });

  const [selected, setSelected] = useState(() => {
    if (openUserId) {
      return convs.find((c) => c.user.id === openUserId) || convs[0];
    }
    return convs[0];
  });

  const [input, setInput] = useState("");
  const [showNewChat, setShowNewChat] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const messagesEndRef = useRef(null);
  const isDark = theme === "dark";

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [selected?.messages]);

  const sendMessage = () => {
    if (!input.trim() || !selected) return;
    const now = new Date().toLocaleTimeString("en-IN", { hour: "2-digit", minute: "2-digit" });
    const newMsg = { sender: "You", text: input.trim(), time: now };
    setConvs((cs) =>
      cs.map((c) =>
        c.id === selected.id
          ? { ...c, messages: [...c.messages, newMsg], lastMessage: input.trim(), time: now }
          : c
      )
    );
    setSelected((s) => ({
      ...s,
      messages: [...(s?.messages || []), newMsg],
      lastMessage: input.trim(),
      time: now,
    }));
    setInput("");
    // Simulate reply
    setTimeout(() => {
      const now2 = new Date().toLocaleTimeString("en-IN", { hour: "2-digit", minute: "2-digit" });
      const replies = ["Got it! 👍", "Sure, let's do this.", "That sounds great!", "I'll check and get back to you.", "Sounds like a plan 🙌"];
      const reply = { sender: selected.user.name, text: replies[Math.floor(Math.random() * replies.length)], time: now2 };
      setConvs((cs) =>
        cs.map((c) =>
          c.id === selected.id
            ? { ...c, messages: [...c.messages, newMsg, reply], lastMessage: reply.text, time: now2 }
            : c
        )
      );
      setSelected((s) => ({ ...s, messages: [...(s?.messages || []), newMsg, reply] }));
    }, 1200);
  };

  const startNewChat = (contact) => {
    const existing = convs.find((c) => c.user.id === contact.id);
    if (existing) { setSelected(existing); setShowNewChat(false); return; }
    const newConv = fresh(contact);
    setConvs((cs) => [newConv, ...cs]);
    setSelected(newConv);
    setShowNewChat(false);
  };

  const suggestMeeting = () => {
    const now = new Date().toLocaleTimeString("en-IN", { hour: "2-digit", minute: "2-digit" });
    const msg = { sender: "You", text: "📅 Meeting Suggestion: How about a 30-min video session this weekend? Let me know what works for you!", time: now };
    setConvs((cs) => cs.map((c) => c.id === selected.id ? { ...c, messages: [...c.messages, msg], lastMessage: msg.text, time: now } : c));
    setSelected((s) => ({ ...s, messages: [...(s?.messages || []), msg] }));
  };

  // Filtered contacts for New Chat modal
  const filteredContacts = ALL_CONTACTS.filter(
    (c) => !convs.some((cv) => cv.user.id === c.id) &&
      c.name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const bg = isDark ? "#0c0c10" : "#F0F2FF";
  const sideBg = isDark ? "rgba(255,255,255,0.03)" : "rgba(255,255,255,0.9)";
  const sideBorder = isDark ? "rgba(255,255,255,0.07)" : "rgba(108,99,255,0.15)";
  const txt = isDark ? "#F0F0FF" : "#1A1A30";
  const mutedTxt = isDark ? "rgba(255,255,255,0.4)" : "rgba(0,0,0,0.4)";

  return (
    <div style={{ height: "100vh", display: "flex", background: bg, fontFamily: "'Inter',sans-serif", color: txt, position: "relative" }}>

      {/* New Chat Modal */}
      {showNewChat && (
        <div style={S.modalOverlay} onClick={() => setShowNewChat(false)}>
          <div style={{ ...S.modal, background: isDark ? "#1a1a28" : "#fff", border: isDark ? "1px solid rgba(255,255,255,0.1)" : "1px solid rgba(108,99,255,0.2)", color: txt }} onClick={(e) => e.stopPropagation()}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
              <h3 style={{ fontSize: "1rem", fontWeight: 700 }}>Start New Chat</h3>
              <button style={S.closeModalBtn} onClick={() => setShowNewChat(false)}><X size={16} /></button>
            </div>
            <div style={{ ...S.modalSearch, background: isDark ? "rgba(255,255,255,0.05)" : "rgba(0,0,0,0.05)", border: isDark ? "1px solid rgba(255,255,255,0.1)" : "1px solid rgba(108,99,255,0.2)" }}>
              <Search size={14} style={{ color: mutedTxt }} />
              <input
                style={{ border: "none", outline: "none", background: "transparent", color: txt, flex: 1, fontSize: "0.88rem", fontFamily: "'Inter',sans-serif" }}
                placeholder="Search contacts..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                autoFocus
              />
            </div>
            <div style={{ maxHeight: 280, overflowY: "auto", marginTop: 12 }}>
              {filteredContacts.length === 0 ? (
                <p style={{ textAlign: "center", color: mutedTxt, padding: "20px 0", fontSize: "0.85rem" }}>All contacts already have conversations</p>
              ) : filteredContacts.map((c) => (
                <div key={c.id} style={S.contactRow} onClick={() => startNewChat(c)}>
                  <div style={{ ...S.smallAvatar, background: c.avatarColor }}>{c.avatar}</div>
                  <div>
                    <p style={{ fontSize: "0.88rem", fontWeight: 600 }}>{c.name}</p>
                    <p style={{ fontSize: "0.72rem", color: mutedTxt }}>{c.role}</p>
                  </div>
                  <div style={{ ...S.onlineDot2, background: c.online ? "#2ecc71" : "#555" }} />
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* LEFT — Conversations list */}
      <div style={{ width: 280, minWidth: 280, borderRight: `1px solid ${sideBorder}`, background: sideBg, display: "flex", flexDirection: "column" }}>
        <div style={{ padding: "20px 16px 12px" }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 14 }}>
            <h2 style={{ fontSize: "1.05rem", fontWeight: 700 }}>Messages</h2>
            <button style={{ ...S.newChatBtn, background: isDark ? "rgba(108,99,255,0.2)" : "rgba(108,99,255,0.12)" }} onClick={() => { setShowNewChat(true); setSearchQuery(""); }}>
              <Plus size={16} /> New
            </button>
          </div>
        </div>

        <div style={{ overflowY: "auto", flex: 1 }}>
          {convs.map((c) => (
            <div
              key={c.id}
              style={{
                padding: "12px 14px",
                cursor: "pointer",
                background: selected?.id === c.id ? (isDark ? "rgba(108,99,255,0.12)" : "rgba(108,99,255,0.08)") : "transparent",
                borderLeft: selected?.id === c.id ? "3px solid #6C63FF" : "3px solid transparent",
                display: "flex", gap: 10, alignItems: "center",
                transition: "background 0.15s",
              }}
              onClick={() => setSelected(c)}
            >
              <div style={{ position: "relative", flexShrink: 0 }}>
                <div style={{ ...S.listAvatar, background: c.user.avatarColor }}>{c.user.avatar}</div>
                <div style={{ ...S.onlineDot2, top: -1, right: -1, background: c.user.online ? "#2ecc71" : "#555" }} />
              </div>
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 3 }}>
                  <p style={{ fontWeight: 600, fontSize: "0.88rem", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{c.user.name}</p>
                  <span style={{ fontSize: "0.7rem", color: mutedTxt, flexShrink: 0, marginLeft: 4 }}>{c.time}</span>
                </div>
                <p style={{ fontSize: "0.76rem", color: mutedTxt, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{c.lastMessage}</p>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* RIGHT — Chat window */}
      {selected ? (
        <div style={{ flex: 1, display: "flex", flexDirection: "column", minWidth: 0 }}>
          {/* Chat header */}
          <div style={{ padding: "16px 24px", borderBottom: `1px solid ${sideBorder}`, display: "flex", alignItems: "center", gap: 12, background: sideBg }}>
            <div style={{ position: "relative" }}>
              <div style={{ ...S.listAvatar, background: selected.user.avatarColor }}>{selected.user.avatar}</div>
              <div style={{ ...S.onlineDot2, bottom: 0, right: -2, top: "auto", background: selected.user.online ? "#2ecc71" : "#555" }} />
            </div>
            <div style={{ flex: 1 }}>
              <p style={{ fontWeight: 700, fontSize: "0.95rem" }}>{selected.user.name}</p>
              <p style={{ fontSize: "0.75rem", color: selected.user.online ? "#2ecc71" : mutedTxt }}>
                {selected.user.online ? "● Online" : "○ Away"} · {selected.user.role}
              </p>
            </div>
            <button style={S.headerActionBtn} title="Voice call"><Phone size={16} /></button>
            <button style={S.headerActionBtn} title="Video call"><Video size={16} /></button>
            <button style={{ ...S.headerActionBtn, color: "#6C63FF", borderColor: "rgba(108,99,255,0.3)" }} onClick={suggestMeeting} title="Suggest meeting">
              <Calendar size={16} /> <span style={{ fontSize: "0.8rem", fontWeight: 600 }}>Meet</span>
            </button>
          </div>

          {/* Messages area */}
          <div style={{ flex: 1, overflowY: "auto", padding: "24px", display: "flex", flexDirection: "column", gap: 12 }}>
            {selected.messages.length === 0 && (
              <div style={{ margin: "auto", textAlign: "center", color: mutedTxt }}>
                <div style={{ fontSize: "2.5rem", marginBottom: 12 }}>👋</div>
                <p style={{ fontSize: "0.92rem" }}>No messages yet. Say hello!</p>
              </div>
            )}
            {selected.messages.map((m, i) => {
              const isMe = m.sender === "You";
              return (
                <div key={i} style={{ display: "flex", flexDirection: isMe ? "row-reverse" : "row", gap: 8, alignItems: "flex-end" }}>
                  {!isMe && (
                    <div style={{ width: 30, height: 30, borderRadius: "50%", background: selected.user.avatarColor, display: "flex", alignItems: "center", justifyContent: "center", fontWeight: 700, color: "#fff", fontSize: "0.75rem", flexShrink: 0 }}>
                      {selected.user.avatar}
                    </div>
                  )}
                  <div>
                    <div style={{
                      padding: "10px 16px", borderRadius: isMe ? "16px 16px 4px 16px" : "16px 16px 16px 4px",
                      background: isMe ? "linear-gradient(135deg,#6C63FF,#00c6ff)" : (isDark ? "rgba(255,255,255,0.07)" : "rgba(108,99,255,0.08)"),
                      color: isMe ? "#fff" : txt,
                      maxWidth: 400, fontSize: "0.88rem", lineHeight: 1.55,
                      boxShadow: isMe ? "0 4px 12px rgba(108,99,255,0.25)" : "none",
                    }}>
                      {m.text}
                    </div>
                    <p style={{ fontSize: "0.68rem", color: mutedTxt, marginTop: 4, textAlign: isMe ? "right" : "left" }}>{m.time}</p>
                  </div>
                </div>
              );
            })}
            <div ref={messagesEndRef} />
          </div>

          {/* Input */}
          <div style={{ padding: "16px 24px", borderTop: `1px solid ${sideBorder}`, background: sideBg }}>
            <div style={{ display: "flex", gap: 10, alignItems: "center" }}>
              <input
                style={{ flex: 1, padding: "12px 16px", borderRadius: 12, border: isDark ? "1px solid rgba(255,255,255,0.1)" : "1px solid rgba(108,99,255,0.2)", background: isDark ? "rgba(255,255,255,0.05)" : "rgba(255,255,255,0.8)", color: txt, outline: "none", fontSize: "0.88rem", fontFamily: "'Inter',sans-serif" }}
                placeholder={`Message ${selected.user.name}...`}
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => e.key === "Enter" && sendMessage()}
              />
              <button style={S.sendBtn} onClick={sendMessage}>
                <Send size={18} />
              </button>
            </div>
          </div>
        </div>
      ) : (
        <div style={{ flex: 1, display: "flex", alignItems: "center", justifyContent: "center", color: mutedTxt }}>
          <p>Select a conversation to start chatting</p>
        </div>
      )}
    </div>
  );
}

const S = {
  modalOverlay: {
    position: "fixed", inset: 0, background: "rgba(0,0,0,0.7)", zIndex: 1000,
    display: "flex", alignItems: "center", justifyContent: "center",
    backdropFilter: "blur(4px)",
  },
  modal: {
    width: 380, borderRadius: 18, padding: "24px",
    boxShadow: "0 24px 64px rgba(0,0,0,0.5)",
  },
  closeModalBtn: {
    background: "rgba(255,255,255,0.1)", border: "none", borderRadius: "50%",
    width: 28, height: 28, display: "flex", alignItems: "center", justifyContent: "center",
    cursor: "pointer", color: "inherit",
  },
  modalSearch: {
    display: "flex", alignItems: "center", gap: 8,
    padding: "10px 14px", borderRadius: 10,
  },
  contactRow: {
    display: "flex", alignItems: "center", gap: 12, padding: "10px 8px",
    borderRadius: 10, cursor: "pointer", position: "relative",
    transition: "background 0.15s",
  },
  smallAvatar: {
    width: 36, height: 36, borderRadius: 10,
    display: "flex", alignItems: "center", justifyContent: "center",
    fontWeight: 700, color: "#fff", fontSize: "0.85rem", flexShrink: 0,
  },
  onlineDot2: {
    position: "absolute", width: 9, height: 9, borderRadius: "50%",
    top: -1, right: -1, border: "2px solid #1a1a28",
  },
  newChatBtn: {
    display: "flex", alignItems: "center", gap: 5, padding: "6px 12px", borderRadius: 8,
    border: "none", color: "#6C63FF", fontWeight: 600, fontSize: "0.8rem",
    cursor: "pointer", fontFamily: "'Inter',sans-serif",
  },
  listAvatar: {
    width: 38, height: 38, borderRadius: 10,
    display: "flex", alignItems: "center", justifyContent: "center",
    fontWeight: 700, color: "#fff", fontSize: "0.88rem",
  },
  headerActionBtn: {
    display: "flex", alignItems: "center", gap: 5,
    padding: "7px 12px", borderRadius: 8,
    background: "transparent", border: "1px solid rgba(255,255,255,0.1)",
    color: "rgba(255,255,255,0.6)", cursor: "pointer",
    fontFamily: "'Inter',sans-serif", transition: "all 0.2s",
  },
  sendBtn: {
    width: 44, height: 44, borderRadius: 12, border: "none", flexShrink: 0,
    background: "linear-gradient(135deg,#6C63FF,#00c6ff)", color: "#fff",
    display: "flex", alignItems: "center", justifyContent: "center",
    cursor: "pointer", boxShadow: "0 4px 12px rgba(108,99,255,0.35)",
  },
};
